// jsc/bindings/bua_jsc_sys.rs
//
// Raw unsafe bindings to the C JSC bridge.
//
// RULES:
//   1. This file contains ALL unsafe. Nothing else in bua-runtime uses unsafe.
//   2. Every extern function is wrapped in a safe abstraction in ffi/context.rs
//   3. Pointer validity is maintained by the wrapper layer, not here.
//   4. This file is only compiled when cfg(jsc_available) is set.
//
// Generated by hand (bindgen output cleaned and annotated).
// When JSC headers change: run `cargo build` which regenerates via build.rs.

#![allow(
    non_camel_case_types,
    non_snake_case,
    dead_code,
    clippy::missing_safety_doc
)]

use std::ffi::c_void;
use std::os::raw::{c_char, c_int};

// ---------------------------------------------------------------------------
// Opaque JSC types
// ---------------------------------------------------------------------------

/// JSC virtual machine group. One per process is typical.
#[repr(C)]
pub struct OpaqueJSContextGroup(c_void);
pub type JSContextGroupRef = *mut OpaqueJSContextGroup;

/// A JSC global execution context (one per agent).
#[repr(C)]
pub struct OpaqueJSContext(c_void);
pub type JSContextRef = *const OpaqueJSContext;
pub type JSGlobalContextRef = *mut OpaqueJSContext;

/// A JS string (ref-counted, UTF-16 internally).
#[repr(C)]
pub struct OpaqueJSString(c_void);
pub type JSStringRef = *mut OpaqueJSString;

/// A JS value (any type).
#[repr(C)]
pub struct OpaqueJSValue(c_void);
pub type JSValueRef = *const OpaqueJSValue;

/// A JS object (subtype of JSValue).
pub type JSObjectRef = *mut OpaqueJSValue;

/// A JS class (used for native object registration).
#[repr(C)]
pub struct OpaqueJSClass(c_void);
pub type JSClassRef = *mut OpaqueJSClass;

// ---------------------------------------------------------------------------
// JSC value types
// ---------------------------------------------------------------------------

pub const K_JSTYPE_UNDEFINED: c_int = 0;
pub const K_JSTYPE_NULL: c_int = 1;
pub const K_JSTYPE_BOOLEAN: c_int = 2;
pub const K_JSTYPE_NUMBER: c_int = 3;
pub const K_JSTYPE_STRING: c_int = 4;
pub const K_JSTYPE_OBJECT: c_int = 5;
pub const K_JSTYPE_SYMBOL: c_int = 6;

// ---------------------------------------------------------------------------
// JSC property attributes
// ---------------------------------------------------------------------------

pub const K_JSPROPERTY_ATTRIBUTE_NONE: c_int = 0;
pub const K_JSPROPERTY_ATTRIBUTE_READ_ONLY: c_int = 2;
pub const K_JSPROPERTY_ATTRIBUTE_DONT_ENUM: c_int = 4;
pub const K_JSPROPERTY_ATTRIBUTE_DONT_DELETE: c_int = 8;

// ---------------------------------------------------------------------------
// Native callback type
// ---------------------------------------------------------------------------

pub type JSObjectCallAsFunctionCallback = unsafe extern "C" fn(
    ctx: JSContextRef,
    function: JSObjectRef,
    thisObject: JSObjectRef,
    argumentCount: usize,
    arguments: *const JSValueRef,
    exception: *mut JSValueRef,
) -> JSValueRef;

// ---------------------------------------------------------------------------
// JSClassDefinition (simplified — full struct is larger)
// ---------------------------------------------------------------------------

#[repr(C)]
pub struct JSClassDefinition {
    pub version: c_int,
    pub attributes: c_int,
    pub class_name: *const c_char,
    pub parent_class: JSClassRef,
    // ... many function pointers omitted for brevity
    // Real: matches <JavaScriptCore/JSObjectRef.h> JSClassDefinition exactly
    pub call_as_function: Option<JSObjectCallAsFunctionCallback>,
    pub finalize: Option<unsafe extern "C" fn(JSObjectRef)>,
    _padding: [*const c_void; 12], // match struct size
}

impl JSClassDefinition {
    pub const fn empty() -> Self {
        Self {
            version: 0,
            attributes: 0,
            class_name: std::ptr::null(),
            parent_class: std::ptr::null_mut(),
            call_as_function: None,
            finalize: None,
            _padding: [std::ptr::null(); 12],
        }
    }
}

