#[inline]
pub unsafe fn jsc_value_protect(ctx: *mut c_void, value: *const c_void) {
    bua_value_protect(ctx, value as *mut _);
}

#[inline]
pub unsafe fn jsc_value_unprotect(ctx: *mut c_void, value: *const c_void) {
    bua_value_unprotect(ctx, value as *mut _);
}

pub unsafe fn jsc_call_as_function(
    ctx: *mut c_void,
    func: *mut c_void,
    this_obj: *mut c_void,
    arg_count: usize,
    arguments: *const *const c_void,
    exception: *mut *mut c_void,
) -> *mut c_void {
    bua_call_function(
        ctx,
        func,
        this_obj,
        arg_count,
        arguments as *const *mut _,
        exception,
    )
}

pub unsafe fn jsc_make_deferred_promise(
    ctx: *mut c_void,
    resolve: *mut *mut c_void,
    reject: *mut *mut c_void,
    exception: *mut *mut c_void,
) -> *mut c_void {
    bua_make_promise(ctx, resolve, reject, exception)
}

// ---------------------------------------------------------------------------
// Safe string conversion helpers (the only non-trivial unsafe in this file)
// ---------------------------------------------------------------------------

/// Convert a Rust &str to a null-terminated CString, call f, return result.
/// Panics if the string contains interior nulls (JS strings shouldn't).
pub fn with_cstr<T>(s: &str, f: impl FnOnce(*const c_char) -> T) -> T {
    let cstr = std::ffi::CString::new(s).expect("string contains interior null");
    f(cstr.as_ptr())
}

/// Convert a C string returned by JSC (not null-terminated length-based) to String.
/// Frees the C string via bua_string_free after copying.
///
/// # Safety
/// - `ptr` must be a valid pointer returned by a bua_* function
/// - `len` must match the actual length
pub unsafe fn cstr_to_string(ptr: *mut c_char, len: usize) -> String {
    if ptr.is_null() || len == 0 {
        return String::new();
    }
    let slice = std::slice::from_raw_parts(ptr as *const u8, len);
    let s = String::from_utf8_lossy(slice).into_owned();
    bua_string_free(ptr);
    s
}

/// Read a null-terminated C string without taking ownership.
///
/// # Safety
/// - `ptr` must be valid and null-terminated
pub unsafe fn read_cstr(ptr: *const c_char) -> String {
    if ptr.is_null() {
        return String::new();
    }
    std::ffi::CStr::from_ptr(ptr).to_string_lossy().into_owned()
}
